diff --git a/llvm/lib/Transforms/Utils/SimplifyIndVar.cpp b/llvm/lib/Transforms/Utils/SimplifyIndVar.cpp
index 7b9c5c77cbe9..9132cf90720a 100644
--- a/llvm/lib/Transforms/Utils/SimplifyIndVar.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyIndVar.cpp
@@ -1487,6 +1487,22 @@ WidenIV::getExtendedOperandRecurrence(WidenIV::NarrowIVDefUse DU) {
   const unsigned ExtendOperIdx = Op->Operands[0] == DU.NarrowDef ? 1 : 0;
   assert(Op->Operands[1 - ExtendOperIdx] == DU.NarrowDef && "bad DU");

+  // Avoid hoisting a zero/sign-extend across an arithmetic operation if doing so
+  // would change wrap semantics. In particular, for additions like
+  // zext(add iN %iv, %iv), widening to add(zext(%iv), zext(%iv)) computes in the
+  // wide type and loses the narrow wrap unless we can prove no unsigned/signed
+  // wrap. Guard this by requiring appropriate no-wrap on the original op when
+  // both operands are derived from the same narrow IV.
+  // This addresses miscompilations where the widened form produces a different
+  // constant exit value for loops that do not take the backedge.
+  if (Op->Opcode == Instruction::Add) {
+    Value *OpL = Op->Operands[0];
+    Value *OpR = Op->Operands[1];
+    bool BothFromSameNarrowIV = (OpL == DU.NarrowDef) && (OpR == DU.NarrowDef);
+    if (BothFromSameNarrowIV && !Op->IsNUW && !Op->IsNSW) {
+      return {nullptr, ExtendKind::Unknown};
+    }
+  }
   ExtendKind ExtKind = getExtendKind(DU.NarrowDef);
   if (!(ExtKind == ExtendKind::Sign && Op->IsNSW) &&
       !(ExtKind == ExtendKind::Zero && Op->IsNUW)) {
